member.example:
Bind the RawImage texture using a serialized binder field — the target RawImage is assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private RawImageTextureBinder _texture;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public Texture _texture;
    }


Bind the RawImage texture by constructing the binder in code.

    [View]
    public partial class ExampleView
    {
        [SerializeField] private RawImage _rawImage;
        
        private RawImageTextureBinder Texture =>
            new(_rawImage);
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public Texture _texture;
    }

Switch the RawImage texture between two values using a serialized binder field — the target RawImage is assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private RawImageTextureSwitcherBinder _isSelected;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public bool _isSelected;
    }


Switch the RawImage texture between two values by constructing the binder in code.

    [View]
    public partial class ExampleView
    {
        [SerializeField] 
        private RawImage _rawImage;
        
        [SerializeField] 
        private Texture _selectedTexture;
        
        [SerializeField] 
        private Texture _defaultTexture;
        
        private RawImageTextureSwitcherBinder IsSelected => new(
            _rawImage, _selectedTexture, _defaultTexture);
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public bool _isSelected;
    }
